def test_node_lock_rejects_missing_registry_integrity(tmp_path: Path):
    manifest = {
        "name": "fixture",
        "version": "1.0.0",
        "dependencies": {"fixture": "1.0.0"},
    }
    lock = {
        "name": "fixture",
        "version": "1.0.0",
        "lockfileVersion": 3,
        "packages": {
            "": manifest,
            "node_modules/fixture": {"version": "1.0.0"},
        },
    }
    _write_json(tmp_path / "package.json", manifest)
    lock_path = _write_json(tmp_path / "package-lock.json", lock)
    subprocess.run(["git", "init", "-q"], cwd=tmp_path, check=True)
    subprocess.run(
        ["git", "add", "package.json", "package-lock.json"], cwd=tmp_path, check=True
    )
    policy = {"node_projects": [{"name": "fixture", "path": "."}]}
    with pytest.raises(GATE.SupplyChainError, match="missing Node source"):
        GATE.verify_node_locks(tmp_path, policy)

    lock["packages"]["node_modules/fixture"].update(
        {
            "resolved": "https://registry.npmjs.org/fixture/-/fixture-1.0.0.tgz",
            "integrity": "sha512-" + base64.b64encode(b"x" * 64).decode(),
        }
    )
    _write_json(lock_path, lock)
    GATE.verify_node_locks(tmp_path, policy)


def test_materialized_compose_images_reject_wrong_backend_repository(tmp_path: Path):
    manifests = ("docker-compose.yml", "docker-compose.deploy.yml")
    references = []
    for manifest in manifests:
        references.extend(
            repository + ":fixture@sha256:" + "a" * 64
            for repository in GATE._manifest_literal_repositories(REPO / manifest)
        )
    references.extend(
        repository + ":fixture@sha256:" + "b" * 64
        for repository in (
            "ghcr.io/jungt72/sealai-backend-v2",
            "ghcr.io/jungt72/sealai-frontend",
            "ghcr.io/jungt72/sealai-keycloak",
        )
    )
    images = tmp_path / "images.txt"
    images.write_text("\n".join(references) + "\n", encoding="utf-8")
    GATE.verify_materialized_images(manifests, images)

    backend_ref = next(
        reference
        for reference in references
        if reference.startswith("ghcr.io/jungt72/sealai-backend-v2:")
    )
    images.write_text("\n".join(references + [backend_ref]) + "\n", encoding="utf-8")
    GATE.verify_materialized_images(manifests, images)

    images.write_text(
        images.read_text(encoding="utf-8").replace(
            "ghcr.io/jungt72/sealai-backend-v2", "ghcr.io/example/backend-v2"
        ),
        encoding="utf-8",
    )
    with pytest.raises(GATE.SupplyChainError, match="do not match policy"):
        GATE.verify_materialized_images(manifests, images)
